const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let n;
let arr;
rl.on('line', (input) => {
    if (!n) {
        n = parseInt(input);
    } else {
        arr = input.split(' ').map(Number);
        arr.sort((a, b) => b - a);
        let sum = 0;
        for (let i = 0; i < n; i++) {
            sum += arr[i];
        }
        console.log(sum);
        rl.close();
    }
});
